public class Solution { public bool IsAnagram(string s, string t) { if (s.Length != t.Length) return false; Dictionary<char, int> Dict = new Dictionary<char, int>(); foreach (char c in s) { int value; if (!Dict.TryGetValue(c, out value)) Dict[c] = 1; else Dict[c]++; } foreach (char c in t) { int value; if (!Dict.TryGetValue(c, out value)) return false; if (Dict.TryGetValue(c, out value)) Dict[c]--; if (Dict[c] < 0) return false; } return true; } }